public SqlBuilder select(boolean isDistinct, Collection<String> fields) {
		sql.append("SELECT ");
		if (isDistinct) {
			sql.append("DISTINCT ");
		}

		if (CollectionUtil.isEmpty(fields)) {
			sql.append("*");
		} else {
			if (null != wrapper) {
				// 包装字段名
				fields = wrapper.wrap(fields);
			}
			sql.append(CollectionUtil.join(fields, StrUtil.COMMA));
		}

		return this;
	}

