synchronized public static void restart() {
		if (null != crontabSetting) {
			//重新读取配置文件
			crontabSetting.load();
		}
		if (scheduler.isStarted()) {
			//关闭并清除已有任务
			scheduler.stop(true);
		}

		//重新加载任务
		schedule(crontabSetting);
		//重新启动
		scheduler.start();
	}

