public static byte[] longToBytes(long longValue) {
		// Magic number 8 should be defined as Long.SIZE / Byte.SIZE
		final byte[] result = new byte[8];
		for (int i = 7; i >= 0; i--) {
			result[i] = (byte) (longValue & 0xFF);
			longValue >>= 8;
		}
		return result;
	}

